SELECT gmap_id, COUNT(*) as high_rating_count FROM review WHERE rating >= 4.5 AND (
  COALESCE(
    TRY_STRPTIME(time, '%Y-%m-%d %H:%M:%S'),
    TRY_STRPTIME(time, '%B %d, %Y at %I:%M %p'),
    TRY_STRPTIME(time, '%d %B %Y, %H:%M'),
    TRY_STRPTIME(time, '%d %b %Y, %H:%M'),
    TRY_STRPTIME(time, '%B %d, %Y at %H:%M'),
    TRY_STRPTIME(time, '%m/%d/%Y %H:%M:%S')
  ) BETWEEN DATE '2019-01-01' AND DATE '2019-12-31'
) GROUP BY gmap_id ORDER BY high_rating_count DESC, gmap_id ASC LIMIT 3;
